import{_ as a,o as n,c as e,ak as o}from"./chunks/framework.DLt_otXO.js";const y=JSON.parse('{"title":"路由匹配","description":"","frontmatter":{"title":"路由匹配","date":"2021-12-30T16:08:07.000Z","permalink":"/pages/38f392/","categories":["框架","VueRouter"],"tags":[null]},"headers":[],"relativePath":"框架/VueRouter/路由匹配的语法.md","filePath":"框架/VueRouter/路由匹配的语法.md","lastUpdated":1777258973000}'),l={name:"框架/VueRouter/路由匹配的语法.md"};function p(t,s,c,r,d,E){return n(),e("div",null,[...s[0]||(s[0]=[o(`<h2 id="_1-在参数中自定义规则" tabindex="-1">1. 在参数中自定义规则 <a class="header-anchor" href="#_1-在参数中自定义规则" aria-label="Permalink to “1. 在参数中自定义规则”">​</a></h2><p>括号中为参数指定一个自定义的正则</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki github-dark" style="background-color:#24292e;color:#e1e4e8;" tabindex="0" dir="ltr"><code><span class="line"><span style="color:#F97583;">const</span><span style="color:#79B8FF;"> routes</span><span style="color:#F97583;"> =</span><span style="color:#E1E4E8;"> [</span></span>
<span class="line"><span style="color:#6A737D;">  // /:orderId -&gt; 仅匹配数字</span></span>
<span class="line"><span style="color:#E1E4E8;">  { path: </span><span style="color:#9ECBFF;">&#39;/:orderId(</span><span style="color:#79B8FF;">\\\\</span><span style="color:#9ECBFF;">d+)&#39;</span><span style="color:#E1E4E8;"> },</span></span>
<span class="line"><span style="color:#6A737D;">  // /:productName -&gt; 匹配其他任何内容</span></span>
<span class="line"><span style="color:#E1E4E8;">  { path: </span><span style="color:#9ECBFF;">&#39;/:productName&#39;</span><span style="color:#E1E4E8;"> },</span></span>
<span class="line"><span style="color:#E1E4E8;">]</span></span></code></pre></div><p>现在，转到 <code>/25</code> 将匹配 <code>/:orderId</code>，其他情况将会匹配 <code>/:productName</code>。<code>routes</code> 数组的顺序并不重要。</p><h2 id="_2-可重复的参数" tabindex="-1">2. 可重复的参数 <a class="header-anchor" href="#_2-可重复的参数" aria-label="Permalink to “2. 可重复的参数”">​</a></h2><p>如果你需要匹配具有多个部分的路由，如 <code>/first/second/third</code>，你应该用 <code>*</code>（<strong>0 个或多个</strong>）和 <code>+</code>（<strong>1 个或多个</strong>）将参数标记为可重复：</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki github-dark" style="background-color:#24292e;color:#e1e4e8;" tabindex="0" dir="ltr"><code><span class="line"><span style="color:#F97583;">const</span><span style="color:#79B8FF;"> routes</span><span style="color:#F97583;"> =</span><span style="color:#E1E4E8;"> [</span></span>
<span class="line"><span style="color:#6A737D;">  // /:chapters -&gt;  匹配 /one, /one/two, /one/two/three, 等</span></span>
<span class="line"><span style="color:#E1E4E8;">  { path: </span><span style="color:#9ECBFF;">&#39;/:chapters+&#39;</span><span style="color:#E1E4E8;"> },</span></span>
<span class="line"><span style="color:#6A737D;">  // /:chapters -&gt; 匹配 /, /one, /one/two, /one/two/three, 等</span></span>
<span class="line"><span style="color:#E1E4E8;">  { path: </span><span style="color:#9ECBFF;">&#39;/:chapters*&#39;</span><span style="color:#E1E4E8;"> },</span></span>
<span class="line"><span style="color:#E1E4E8;">]</span></span></code></pre></div><p>这些也可以通过在右括号后添加它们与自定义正则结合使用：</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki github-dark" style="background-color:#24292e;color:#e1e4e8;" tabindex="0" dir="ltr"><code><span class="line"><span style="color:#F97583;">const</span><span style="color:#79B8FF;"> routes</span><span style="color:#F97583;"> =</span><span style="color:#E1E4E8;"> [</span></span>
<span class="line"><span style="color:#6A737D;">  // 仅匹配数字</span></span>
<span class="line"><span style="color:#6A737D;">  // 匹配 /1, /1/2, 等</span></span>
<span class="line"><span style="color:#E1E4E8;">  { path: </span><span style="color:#9ECBFF;">&#39;/:chapters(</span><span style="color:#79B8FF;">\\\\</span><span style="color:#9ECBFF;">d+)+&#39;</span><span style="color:#E1E4E8;"> },</span></span>
<span class="line"><span style="color:#6A737D;">  // 匹配 /, /1, /1/2, 等</span></span>
<span class="line"><span style="color:#E1E4E8;">  { path: </span><span style="color:#9ECBFF;">&#39;/:chapters(</span><span style="color:#79B8FF;">\\\\</span><span style="color:#9ECBFF;">d+)*&#39;</span><span style="color:#E1E4E8;"> },</span></span>
<span class="line"><span style="color:#E1E4E8;">]</span></span></code></pre></div><h2 id="_3-可选参数" tabindex="-1">3.可选参数 <a class="header-anchor" href="#_3-可选参数" aria-label="Permalink to “3.可选参数”">​</a></h2><p>你也可以通过使用 <code>?</code>修饰符(0 个或 1 个)将一个参数标记为<code>可选</code>：</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki github-dark" style="background-color:#24292e;color:#e1e4e8;" tabindex="0" dir="ltr"><code><span class="line"><span style="color:#F97583;">const</span><span style="color:#79B8FF;"> routes</span><span style="color:#F97583;"> =</span><span style="color:#E1E4E8;"> [</span></span>
<span class="line"><span style="color:#6A737D;">  // 匹配 /users 和 /users/posva</span></span>
<span class="line"><span style="color:#E1E4E8;">  { path: </span><span style="color:#9ECBFF;">&#39;/users/:userId?&#39;</span><span style="color:#E1E4E8;"> },</span></span>
<span class="line"><span style="color:#6A737D;">  // 匹配 /users 和 /users/42</span></span>
<span class="line"><span style="color:#E1E4E8;">  { path: </span><span style="color:#9ECBFF;">&#39;/users/:userId(</span><span style="color:#79B8FF;">\\\\</span><span style="color:#9ECBFF;">d+)?&#39;</span><span style="color:#E1E4E8;"> },</span></span>
<span class="line"><span style="color:#E1E4E8;">]</span></span></code></pre></div><p>请注意，<code>*</code> 在技术上也标志着一个参数是可选的，但 <code>?</code> 参数不能重复</p>`,13)])])}const u=a(l,[["render",p]]);export{y as __pageData,u as default};
